void ui_event_Door_open(lv_event_t * e)
{
    lv_event_code_t event_code = lv_event_get_code(e);

    if(event_code == LV_EVENT_SCREEN_LOADED) {
        dooropen_Animation(ui_door_open_img, 0);
        dooropen_Animation(ui_Door_open_text, 0);
    }
    if(event_code == LV_EVENT_GESTURE &&  lv_indev_get_gesture_dir(lv_indev_get_act()) == LV_DIR_LEFT) {
        lv_indev_wait_release(lv_indev_get_act());
        _ui_screen_change(&ui_Drive, LV_SCR_LOAD_ANIM_FADE_ON, 500, 0, &ui_Drive_screen_init);
    }
    if(event_code == LV_EVENT_GESTURE &&  lv_indev_get_gesture_dir(lv_indev_get_act()) == LV_DIR_RIGHT) {
        lv_indev_wait_release(lv_indev_get_act());
        _ui_screen_change(&ui_Charge, LV_SCR_LOAD_ANIM_FADE_ON, 500, 0, &ui_Charge_screen_init);
    }
}

